def search_local_dataset(query: str, limit: int = 15, diet: str = "None") -> list[dict]:
    """
    Search the local dataset for products whose name contains any word from the query.
    Returns a list of matching product dicts in the same format as grocery_api results.
    """
    from dietary_filters import filter_products_by_diet

    query_words = [w for w in query.lower().split() if len(w) > 2]
    if not query_words:
        return []

    matched = []
    seen: set[str] = set()

    for p in LOCAL_PRODUCTS:
        name_lower = p["product_name"].lower()
        if any(w in name_lower for w in query_words):
            norm = name_lower.strip()
            if norm not in seen:
                seen.add(norm)
                matched.append(p)

    filtered = filter_products_by_diet(matched, diet)
    return filtered[:limit]
